from __future__ import annotations
from dataclasses import dataclass
from enum import Enum
from typing import Optional
import time

class BudgetStatus(Enum):
    NORMAL   = "normal"
    WARN     = "warn"
    CRITICAL = "critical"
    BLOCKED  = "blocked"

@dataclass
class BudgetConfig:
    team:              str
    monthly_cap_usd:   float
    warn_pct:          float = 0.80
    critical_pct:      float = 0.90
    exempt_types:      frozenset[str] = frozenset({"exempt", "health-check"})

@dataclass
class GuardrailDecision:
    status:          BudgetStatus
    utilisation:     float
    spent_usd:       float
    cap_usd:         float
    rate_limit_pct:  Optional[float]  # None = no limit; 0.5 = half normal rate
    allow:           bool
    message:         str

class BudgetGuardrail:
    def __init__(self, configs: list[BudgetConfig]) -> None:
        self._configs = {c.team: c for c in configs}

    def check(self, team: str, request_type: str) -> GuardrailDecision:
        config = self._configs.get(team)
        if config is None:
            # No budget defined — allow with a warning metric
            return GuardrailDecision(
                status=BudgetStatus.NORMAL, utilisation=0.0,
                spent_usd=0.0, cap_usd=0.0,
                rate_limit_pct=None, allow=True,
                message=f"No budget configured for team '{team}' — allowing"
            )
        spent   = get_spent_usd(team)
        util    = spent / config.monthly_cap_usd if config.monthly_cap_usd else 0.0
        is_exempt = request_type in config.exempt_types

        if util >= 1.0 and not is_exempt:
            return GuardrailDecision(
                status=BudgetStatus.BLOCKED, utilisation=util,
                spent_usd=spent, cap_usd=config.monthly_cap_usd,
                rate_limit_pct=None, allow=False,
                message=(
                    f"Team '{team}' has reached its monthly LLM budget "
                    f"(${config.monthly_cap_usd:,.2f}). "
                    "Request a budget increase via the FinOps portal or use an override token."
                )
            )
        if util >= config.critical_pct:
            return GuardrailDecision(
                status=BudgetStatus.CRITICAL, utilisation=util,
                spent_usd=spent, cap_usd=config.monthly_cap_usd,
                rate_limit_pct=0.5, allow=True,
                message=f"Team '{team}' is at {util:.0%} of monthly budget. Rate limiting to 50%."
            )
        if util >= config.warn_pct:
            return GuardrailDecision(
                status=BudgetStatus.WARN, utilisation=util,
                spent_usd=spent, cap_usd=config.monthly_cap_usd,
                rate_limit_pct=None, allow=True,
                message=f"Team '{team}' is at {util:.0%} of monthly budget."
            )
        return GuardrailDecision(
            status=BudgetStatus.NORMAL, utilisation=util,
            spent_usd=spent, cap_usd=config.monthly_cap_usd,
            rate_limit_pct=None, allow=True, message="ok"
        )

import datetime, jwt, os

OVERRIDE_SECRET = os.environ["BUDGET_OVERRIDE_SECRET"]  # 256-bit secret

def issue_override_token(
    team:              str,
    extra_budget_usd:  float,
    approver:          str,
    ttl_minutes:       int = 120,
) -> str:
    payload = {
        "sub":   team,
        "type":  "budget_override",
        "extra": extra_budget_usd,
        "by":    approver,
        "iat":   datetime.datetime.utcnow(),
        "exp":   datetime.datetime.utcnow() + datetime.timedelta(minutes=ttl_minutes),
    }
    return jwt.encode(payload, OVERRIDE_SECRET, algorithm="HS256")

def validate_override_token(token: str, team: str) -> dict | None:
    try:
        claims = jwt.decode(token, OVERRIDE_SECRET, algorithms=["HS256"])
        if claims.get("sub") != team or claims.get("type") != "budget_override":
            return None
        return claims
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None

